// Filter and score RSS items for relevance to restaurant/burger industry
// Returns top 5 most relevant recent articles

var items = $input.all();
var now = Date.now();
var TWO_WEEKS_MS = 14 * 24 * 60 * 60 * 1000;

var HIGH_VALUE_KEYWORDS = [
  'burger', 'burgers', 'hamburger', 'smash burger', 'craft burger',
  'restaurant trends', 'menu innovation', 'customer experience',
  'food trends', 'dining trends', 'fast casual', 'quick service',
  'restaurant marketing', 'loyalty program', 'local restaurant',
  'beef', 'protein', 'gourmet', 'artisan', 'handcrafted'
];

var MEDIUM_VALUE_KEYWORDS = [
  'restaurant', 'dining', 'food service', 'hospitality', 'menu',
  'customer', 'revenue', 'profit', 'sales', 'growth',
  'social media', 'delivery', 'takeout', 'online ordering',
  'staff', 'labor', 'operations', 'supply chain', 'ingredient',
  'sustainability', 'local', 'community', 'brand'
];

function scoreItem(item) {
  var text = [
    (item.json.title || ''),
    (item.json.description || ''),
    (item.json.summary || ''),
    (item.json.content || '')
  ].join(' ').toLowerCase();

  var score = 0;
  var k;

  for (k = 0; k < HIGH_VALUE_KEYWORDS.length; k++) {
    if (text.indexOf(HIGH_VALUE_KEYWORDS[k].toLowerCase()) !== -1) score += 3;
  }
  for (k = 0; k < MEDIUM_VALUE_KEYWORDS.length; k++) {
    if (text.indexOf(MEDIUM_VALUE_KEYWORDS[k].toLowerCase()) !== -1) score += 1;
  }

  return score;
}

function parseDate(dateStr) {
  if (!dateStr) return 0;
  var d = new Date(dateStr);
  return isNaN(d.getTime()) ? 0 : d.getTime();
}

var scored = items.map(function(item) {
  var pubDate = parseDate(item.json.pubDate || item.json.isoDate || item.json.date);
  var age = now - pubDate;
  var isRecent = pubDate > 0 ? age <= TWO_WEEKS_MS : true;
  return {
    json: item.json,
    _score: scoreItem(item),
    _pubDate: pubDate,
    _isRecent: isRecent
  };
}).filter(function(item) {
  return item._isRecent && item._score > 0;
}).sort(function(a, b) {
  return b._score - a._score || b._pubDate - a._pubDate;
});

var seen = {};
var deduped = [];
var i;
for (i = 0; i < scored.length; i++) {
  var key = (scored[i].json.title || '').toLowerCase().trim();
  if (!seen[key]) {
    seen[key] = true;
    deduped.push(scored[i]);
  }
}

var top5 = deduped.slice(0, 5);

if (top5.length === 0) {
  var fallback = items.sort(function(a, b) {
    var da = parseDate(a.json.pubDate || a.json.isoDate);
    var db = parseDate(b.json.pubDate || b.json.isoDate);
    return db - da;
  }).slice(0, 5);
  return fallback.map(function(item) {
    return {
      json: {
        title: item.json.title || 'Untitled',
        link: item.json.link || item.json.url || '',
        description: item.json.description || item.json.summary || item.json.content || '',
        source: item.json.source || 'Industry News',
        pubDate: item.json.pubDate || item.json.isoDate || '',
        score: 0
      }
    };
  });
}

return top5.map(function(item) {
  var desc = (item.json.description || item.json.summary || item.json.content || '');
  desc = desc.replace(/<[^>]*>/g, '').substring(0, 500);
  return {
    json: {
      title: item.json.title || 'Untitled',
      link: item.json.link || item.json.url || '',
      description: desc,
      source: item.json.source || 'Industry News',
      pubDate: item.json.pubDate || item.json.isoDate || '',
      score: item._score
    }
  };
});

// Aggregate all top articles into a single item for the AI prompt
var items = $input.all();

var articleSummaries = items.map(function(item, i) {
  var lines = [
    'Article ' + (i + 1) + ':',
    'Title: ' + item.json.title,
    'Source: ' + item.json.source,
    'Published: ' + item.json.pubDate,
    'Summary: ' + item.json.description,
    'URL: ' + item.json.link
  ];
  return lines.join('\n');
}).join('\n\n---\n\n');

var sourceLinks = items.map(function(item) {
  return '- ' + item.json.title + ' (' + item.json.link + ')';
}).join('\n');

var today = new Date().toISOString().split('T')[0];

var promptContent = 'Today is ' + today + '. Based on the following trending articles from the restaurant and hospitality industry, write TWO separate, fully publish-ready blog posts for the 80/20 Burgers website. Each post should cover a different angle from the articles.' +
  '\n\nTRENDING INDUSTRY ARTICLES:\n\n' + articleSummaries +
  '\n\n---\n\nWRITE TWO COMPLETE BLOG POSTS. Separate them with:\n\n===== BLOG POST 2 =====\n\nEach blog post must:' +
  '\n1. Have a compelling, SEO-friendly title (include relevant keywords naturally)' +
  '\n2. Open with a strong hook that connects the industry trend to why it matters to burger lovers and 80/20 Burgers specifically' +
  '\n3. Have 4-5 fully developed sections with ## headers, each section being 150-200 words of real substance — not summaries, actual storytelling and perspective' +
  '\n4. Weave in specific callouts to 80/20 Burgers approach, menu philosophy, ingredients, or customer experience throughout' +
  '\n5. Include at least one concrete, specific detail or anecdote per section that makes it feel real and local (not generic)' +
  '\n6. Close with a strong call-to-action (visit us, try a burger, follow us on social, etc.)' +
  '\n7. Be 850-1000 words — fully fleshed out and ready to post with only a light review needed' +
  '\n8. Use markdown formatting throughout' +
  '\n9. End with a Sources and Inspiration section listing the original articles' +
  '\n\nThe two posts must take different angles — one customer-facing and lifestyle-oriented, the other industry-perspective and thought leadership.' +
  '\n\nSOURCE ARTICLES TO CITE:\n' + sourceLinks +
  '\n\nWrite both complete blog posts now:';

return [{
  json: {
    articleSummaries: articleSummaries,
    today: today,
    articleCount: items.length,
    sourceLinks: sourceLinks,
    promptContent: promptContent
  }
}];

// Extract the blog post text from Claude's API response
var response = $input.first().json;
var blogPost = '';

if (response.content && response.content.length > 0) {
  blogPost = response.content[0].text || '';
} else if (response.error) {
  throw new Error('Anthropic API error: ' + JSON.stringify(response.error));
} else {
  throw new Error('Unexpected response from Anthropic API: ' + JSON.stringify(response));
}

var today = new Date().toISOString().split('T')[0];
var fileName = '80-20-Blog-' + today + '.md';

return [{
  json: {
    blogPost: blogPost,
    fileName: fileName,
    today: today,
    wordCount: blogPost.split(/\s+/).length
  }
}];

// Convert blog post text to binary data for Google Drive upload
var blogData = $input.first().json;
var content = blogData.blogPost;
var fileName = blogData.fileName;

var buffer = Buffer.from(content, 'utf8');
var binaryData = await helpers.prepareBinaryData(buffer, fileName, 'text/markdown');

return [{
  json: {
    fileName: fileName,
    wordCount: blogData.wordCount,
    today: blogData.today
  },
  binary: {
    data: binaryData
  }
}];

// Final summary node - outputs confirmation
var blogData = $('Extract Blog Post Text').first().json;

return [{
  json: {
    status: 'success',
    message: '80/20 Burgers weekly blog post generated and saved to Google Drive.',
    fileName: blogData.fileName,
    wordCount: blogData.wordCount,
    generatedAt: new Date().toISOString()
  }
}];
